// ── Compose functions ──

function replaceName(template, name) {
  return template.replace(/\{name\}/g, name)
}

export function getSpeciesSnippet(species, name) {
  if (!species?.name) return ''
  return replaceName(SPECIES_SNIPPETS[species.name] || '', name)
}

export function getCultureSnippet(culture, name) {
  if (!culture?.name) return ''
  return replaceName(CULTURE_SNIPPETS[culture.name] || '', name)
}

export function getProfessionSnippet(profession, name) {
  if (!profession?.name) return ''
  const profName = profession.name
  // Try exact match first
  if (PROFESSION_SNIPPETS[profName]) {
    return replaceName(PROFESSION_SNIPPETS[profName], name)
  }
  // Try keyword fallback
  for (const fb of PROFESSION_KEYWORD_FALLBACKS) {
    if (fb.keywords.some(kw => profName.includes(kw))) {
      return replaceName(fb.snippet, name)
    }
  }
  // Generic fallback
  return replaceName(`Als ${profName} hat {name} eine besondere Ausbildung genossen, die den weiteren Lebensweg prägte.`, name)
}

export function composeTraitSentence(advantages, disadvantages, name) {
  const parts = []

  // Check advantages (max 2 flavor sentences)
  let advCount = 0
  for (const adv of (advantages || [])) {
    if (advCount >= 2) break
    const advName = adv.name || adv
    // Try exact match
    if (ADVANTAGE_FLAVORS[advName]) {
      parts.push(replaceName(ADVANTAGE_FLAVORS[advName], name))
      advCount++
      continue
    }
    // Try prefix match (e.g. "Begabung in Klettern" matches "Begabung")
    for (const [key, tmpl] of Object.entries(ADVANTAGE_FLAVORS)) {
      if (advName.startsWith(key)) {
        parts.push(replaceName(tmpl, name))
        advCount++
        break
      }
    }
  }

  // Check disadvantages (max 1 flavor sentence)
  let disCount = 0
  for (const dis of (disadvantages || [])) {
    if (disCount >= 1) break
    const disName = dis.name || dis
    if (DISADVANTAGE_FLAVORS[disName]) {
      parts.push(replaceName(DISADVANTAGE_FLAVORS[disName], name))
      disCount++
      continue
    }
    for (const [key, tmpl] of Object.entries(DISADVANTAGE_FLAVORS)) {
      if (disName.startsWith(key)) {
        parts.push(replaceName(tmpl, name))
        disCount++
        break
      }
    }
  }

  return parts.join(' ')
}

export function composeBackgroundDraft({ species, culture, profession, advantages, disadvantages, characterName }) {
  const name = characterName || '[Name]'
  const parts = []

  const speciesSnippet = getSpeciesSnippet(species, name)
  if (speciesSnippet) parts.push(speciesSnippet)

  const cultureSnippet = getCultureSnippet(culture, name)
  if (cultureSnippet) parts.push(cultureSnippet)

  const profSnippet = getProfessionSnippet(profession, name)
  if (profSnippet) parts.push(profSnippet)

  const traitSentence = composeTraitSentence(advantages, disadvantages, name)
  if (traitSentence) parts.push(traitSentence)

  return parts.join('\n\n')
}
